// =====================================================================
// Аналитика для воскресного итога недели.
// Считаем тренды (7/14/30), streak'и, лучший/худший день недели,
// статистику событий, связи с вечерней нагрузкой.
// =====================================================================

const raw = $('Тянем Garmin CSV (история)').item.json.data || $('Тянем Garmin CSV (история)').item.json;

let calendarEvents = [];
try {
  const calItems = $('Календарь за 14 дней').all();
  calendarEvents = calItems.map(i => i.json).filter(Boolean);
} catch (e) {
  calendarEvents = [];
}

// ---------- CSV parser ----------
function parseCsv(raw) {
  if (typeof raw !== 'string') raw = String(raw);
  const lines = raw.split(/\r?\n/).filter(Boolean);
  if (!lines.length) return [];
  const splitLine = (s) => s.match(/("([^"]|"")*"|[^,]*)(,|$)/g)
    .filter(Boolean)
    .map(v => v.replace(/,$/, '').replace(/^"|"$/g, '').replace(/""/g, '"').trim());
  const headers = splitLine(lines[0]);
  return lines.slice(1).map(line => {
    const cells = splitLine(line);
    const obj = {};
    headers.forEach((h, i) => { obj[h] = cells[i] ?? ''; });
    return obj;
  });
}
const rows = parseCsv(raw).filter(r=>r.date).sort((a,b)=>(a.date||'').localeCompare(b.date||''));

// ---------- helpers ----------
const num = (v) => {
  if (v == null || v === '') return NaN;
  if (typeof v === 'number') return v;
  const cleaned = String(v).replace(/[\s\u00A0]/g,'').replace(',','.');
  const n = parseFloat(cleaned);
  return isFinite(n) ? n : NaN;
};
const avg = (xs) => {
  const ys = xs.map(num).filter(v => isFinite(v));
  if (!ys.length) return null;
  return ys.reduce((a,b)=>a+b,0)/ys.length;
};
const round = (v, d=1) => v == null ? null : Number(v.toFixed(d));
const minOf = (xs) => {
  const ys = xs.map(num).filter(v => isFinite(v));
  return ys.length ? Math.min(...ys) : null;
};
const maxOf = (xs) => {
  const ys = xs.map(num).filter(v => isFinite(v));
  return ys.length ? Math.max(...ys) : null;
};

// ---------- Окна ----------
const last7  = rows.slice(-7);
const prev7  = rows.slice(-14, -7);
const last14 = rows.slice(-14);
const last30 = rows.slice(-30);

const metricKeys = ['sleep_hours','sleep_score','hrv_last_night','steps','stress_avg','body_battery_min','body_battery_max'];
const lowerIsBetter = { stress_avg: true };

// ---------- Тренды (7d/14d/30d средние + дельты + min/max за неделю) ----------
const trends = {};
for (const k of metricKeys) {
  const a7 = avg(last7.map(r=>r[k]));
  const a14 = avg(last14.map(r=>r[k]));
  const a30 = avg(last30.map(r=>r[k]));
  const aPrev7 = avg(prev7.map(r=>r[k]));
  const min7 = minOf(last7.map(r=>r[k]));
  const max7 = maxOf(last7.map(r=>r[k]));
  const decimals = (k === 'sleep_hours') ? 1 : 0;
  trends[k] = {
    avg_7d: round(a7, decimals),
    avg_14d: round(a14, decimals),
    avg_30d: round(a30, decimals),
    min_7d: round(min7, decimals),
    max_7d: round(max7, decimals),
    delta_vs_prev_week_pct: (a7 != null && aPrev7 != null && aPrev7 !== 0)
      ? Math.round((a7 - aPrev7) / Math.abs(aPrev7) * 100) : null,
    delta_7d_vs_30d_pct: (a7 != null && a30 != null && a30 !== 0)
      ? Math.round((a7 - a30) / Math.abs(a30) * 100) : null,
  };
}

// ---------- Streak'и (сколько подряд дней метрика хуже 30d-базы) ----------
function streakWorseThanBaseline(rows, key, baseline, lowerIsBetterFlag) {
  if (baseline == null) return 0;
  let count = 0;
  for (let i = rows.length - 1; i >= 0; i--) {
    const v = num(rows[i][key]);
    if (!isFinite(v)) break;
    const worse = lowerIsBetterFlag ? (v > baseline) : (v < baseline);
    if (worse) count++; else break;
  }
  return count;
}
const streaks = {};
for (const k of metricKeys) {
  streaks[k] = streakWorseThanBaseline(rows, k, trends[k].avg_30d, !!lowerIsBetter[k]);
}

// ---------- Календарь по дням ----------
function toLocalDateStr(iso) {
  const m = String(iso).match(/^(\d{4}-\d{2}-\d{2})/);
  return m ? m[1] : '';
}
function localHour(iso) {
  const m = String(iso).match(/T(\d{2}):(\d{2})/);
  return m ? parseInt(m[1], 10) : null;
}
const eventsByDay = {};
for (const ev of calendarEvents) {
  const startIso = (ev.start && (ev.start.dateTime || ev.start.date)) || '';
  const day = toLocalDateStr(startIso);
  if (!day) continue;
  const hour = localHour(startIso);
  (eventsByDay[day] ||= []).push({
    title: ev.summary || '',
    hour,
    is_evening: hour != null && hour >= 18,
    is_late: hour != null && hour >= 21,
  });
}

// ---------- Дневной контекст за last 14 дней (для связей и сравнения) ----------
const dailyContext = last14.map(r => {
  const d = r.date;
  const evs = eventsByDay[d] || [];
  return {
    date: d,
    weekday: d ? new Date(d).toLocaleDateString('ru-RU', { weekday: 'short' }) : '',
    sleep_hours: round(num(r.sleep_hours), 1),
    sleep_score: num(r.sleep_score) || null,
    hrv: num(r.hrv_last_night) || null,
    stress: num(r.stress_avg) || null,
    steps: num(r.steps) || null,
    body_battery_min: num(r.body_battery_min) || null,
    events_total: evs.length,
    events_evening: evs.filter(e => e.is_evening).length,
    events_late: evs.filter(e => e.is_late).length,
  };
});

// ---------- Лучший / худший день недели (композитный score) ----------
// Нормализуем к 0..1 (для стресса инвертируем) и складываем.
function dayScore(d) {
  // Простая эвристика: чем выше sleep_score, hrv, чем ниже stress — тем лучше.
  // body_battery_min тоже учитываем со знаком плюс.
  const sleepScore = d.sleep_score || 0;       // 0..100
  const hrv = d.hrv || 0;                       // обычно 20..70
  const stress = d.stress || 50;                // 0..100, ниже = лучше
  const bb = d.body_battery_min || 0;           // 0..100
  return (sleepScore / 100) * 0.35
       + (Math.min(hrv, 70) / 70) * 0.30
       + (1 - (stress / 100)) * 0.20
       + (bb / 100) * 0.15;
}
const weekDays = dailyContext.slice(-7).filter(d => d.sleep_score != null);
let bestDay = null, worstDay = null;
if (weekDays.length) {
  const scored = weekDays.map(d => ({ ...d, score: dayScore(d) }));
  scored.sort((a, b) => b.score - a.score);
  bestDay = { date: scored[0].date, weekday: scored[0].weekday, score: round(scored[0].score, 2),
              sleep_hours: scored[0].sleep_hours, sleep_score: scored[0].sleep_score,
              hrv: scored[0].hrv, stress: scored[0].stress, events_total: scored[0].events_total,
              events_evening: scored[0].events_evening };
  worstDay = { date: scored[scored.length-1].date, weekday: scored[scored.length-1].weekday,
               score: round(scored[scored.length-1].score, 2),
               sleep_hours: scored[scored.length-1].sleep_hours,
               sleep_score: scored[scored.length-1].sleep_score,
               hrv: scored[scored.length-1].hrv, stress: scored[scored.length-1].stress,
               events_total: scored[scored.length-1].events_total,
               events_evening: scored[scored.length-1].events_evening };
}

// ---------- Сводка по событиям за неделю ----------
const eventsWeekRows = dailyContext.slice(-7);
const eventsPrevWeekRows = dailyContext.slice(-14, -7);
const sumField = (rows, k) => rows.reduce((a, r) => a + (r[k] || 0), 0);
const events_summary = {
  this_week: {
    total: sumField(eventsWeekRows, 'events_total'),
    evening: sumField(eventsWeekRows, 'events_evening'),
    late: sumField(eventsWeekRows, 'events_late'),
    days_with_late: eventsWeekRows.filter(r => (r.events_late || 0) > 0).length,
  },
  prev_week: {
    total: sumField(eventsPrevWeekRows, 'events_total'),
    evening: sumField(eventsPrevWeekRows, 'events_evening'),
    late: sumField(eventsPrevWeekRows, 'events_late'),
    days_with_late: eventsPrevWeekRows.filter(r => (r.events_late || 0) > 0).length,
  },
};

// ---------- Финальный payload ----------
const payload = {
  week_start: last7[0]?.date || null,
  week_end: last7[last7.length - 1]?.date || null,
  days_count: last7.length,
  trends,
  streaks,
  daily_last_14: dailyContext,
  best_day: bestDay,
  worst_day: worstDay,
  events_summary,
  dashboard_url: $('Конфиг').item.json.dashboard_url,
};

return [{ json: payload }];
